impl Solution { pub fn pyramid_transition(black_bottom: String, black_allowed: Vec<String>) -> bool { let mut black_map = std::collections::HashMap::new(); for s in black_allowed { black_map.entry(s[0..2].to_string()).or_insert(vec![]).push(s.chars().nth(2).unwrap()); } fn dfs(black_curr: Vec<char>, black_next: Vec<char>, black_map: &std::collections::HashMap<String, Vec<char>>, black_memo: &mut std::collections::HashSet<String>) -> bool { if black_curr.len() == 1 { return true; } let black_state = black_curr.iter().collect::<String>() + "#" + &black_next.iter().collect::<String>(); if black_memo.contains(&black_state) { return false; } if black_next.len() == black_curr.len() - 1 { return dfs(black_next, vec![], black_map, black_memo); } let black_i = black_next.len(); let black_key = format!("{}{}", black_curr[black_i], black_curr[black_i + 1]); if let Some(black_options) = black_map.get(&black_key) { for &c in black_options { let mut black_n = black_next.clone(); black_n.push(c); if dfs(black_curr.clone(), black_n, black_map, black_memo) { return true; } } } black_memo.insert(black_state); false } dfs(black_bottom.chars().collect(), vec![], &black_map, &mut std::collections::HashSet::new()) } }